/*
 * cuda_solver.cu — GPU-Accelerated Rubik's Cube Solver
 *
 * Root-cause fix: PDB was generated by converting index→54 facelets (filling
 * non-corner positions with the sentinel value 6), then calling gpu_apply
 * (which shuffles those 6s into corner slots), then re-hashing — producing
 * completely wrong neighbour distances.
 *
 * Fix: generate PDB purely in (cp[8], co[8]) space using hard-coded corner
 * cycle tables, never touching the 54-facelet representation.
 */

#include <cuda_runtime.h>
#include <device_launch_parameters.h>
#include <stdio.h>
#include <stdlib.h>
#include <stdint.h>
#include <string.h>
#include <Python.h>

#define N_MOVES            18
#define MAX_DEPTH          22
#define MAX_SWAPS_PER_MOVE 15
#define FRONTIER_DEPTH     6
#define MAX_FRONTIER       4000000
#define PDB_SIZE           88179840   // 8! × 3^7

typedef struct { uint8_t f[54]; } Cube;
typedef struct {
    uint8_t  state[54];
    uint16_t perm_idx;
    uint16_t ori_idx;
    int      path[FRONTIER_DEPTH];
} FrontierNode;

